mapper.select:
SELECT gl.id, gl.company_id, gl.account_code, gl.fiscal_year, gl.fiscal_month, gl.beginning_debit_balance, gl.beginning_credit_balance, gl.period_debit_amount, gl.period_credit_amount, gl.year_to_date_debit, gl.year_to_date_credit, gl.ending_debit_balance, gl.ending_credit_balance, gl.is_closed, gl.closed_at, gl.created_at, gl.updated_at FROM general_ledger gl
AND gl.company_id = #{companyId}::uuid
AND gl.fiscal_year = #{fiscalYear}
AND gl.fiscal_month = #{fiscalMonth}
AND gl.account_code IN
#{accountCode}
AND gl.is_closed = #{isClosed}
ORDER BY gl.account_code, gl.fiscal_year, gl.fiscal_month

mapper.insert:
INSERT INTO gl_details (
    general_ledger_id, journal_entry_id, posting_date,
    debit_amount, credit_amount, running_balance, description
) VALUES (
    #{generalLedgerId}, #{journalEntryId}, #{postingDate},
    #{debitAmount}, #{creditAmount}, #{runningBalance}, #{description}
)
